#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Properties;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.rollingGiantBlock)]
    public class RollingGiantBlock : EntityBehaviourDefinition
    {
        public RollingGiantBlock(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Update(Entity entity)
        {
            base.Update(entity);
            var rotation = GetRotation(entity);
            rotation += entity.Velocity.x;
            rotation = Mathf.Repeat(rotation, 360);
            SetRotation(entity, rotation);

            entity.SetAnimationFloat("Rotation", rotation);


            bool remove = false;
            if (!entity.IsFacingLeft() && entity.IsEnemyOutsideRight())
            {
                remove = true;
            }
            else if (entity.IsFacingLeft() && entity.IsEnemyOutsideLeft())
            {
                remove = true;
            }
            if (remove)
            {
                entity.Remove();
            }
        }
        public static float GetRotation(Entity entity) => entity.GetProperty<float>(PROP_ROTATION);
        public static void SetRotation(Entity entity, float value) => entity.SetProperty(PROP_ROTATION, value);
        public static readonly VanillaEntityPropertyMeta<float> PROP_ROTATION = new VanillaEntityPropertyMeta<float>("rotation");
    }
}
